import os

ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}


def is_safe_file_name(file_name):
    return not os.path.isabs(file_name) and file_name and '.' in file_name and file_name.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def read_file(file_name):
    if not is_safe_file_name(file_name):
        raise ValueError('Unsafe file name')
    file_path = os.path.join('/var/www/html/uploads', file_name)
    with open(file_path, 'r') as file:
        return file.read()

